oxy_webhelp_navlinks = {"key_management_service-d27248e11296":{"topics":[{"title":"Adding an AWS KMS key manager","shortdesc":"<p class=\"shortdesc\">To manage encryption for archives stored at AWS archival locations, add an AWS KMS         key support to securely manage and store encryption keys, ensuring secure access and         management of sensitive data.<\/p>","href":"saas\/adding_aws_kms_manager.html","attributes":{"data-id":"adding_aws_kms_manager"},"menu":{"hasChildren":false},"tocID":"adding_aws_kms_manager-d27248e11307","next":"adding_aws_kms_manager-d27248e11307"},{"title":"Adding Azure Key Vaults","shortdesc":"<p class=\"shortdesc\">Add an Azure Key Vault to manage encryption for Azure based archives or Rubrik Cloud         Vault. The key vault securely stores your encryption keys and controls access to sensitive         data.<\/p>","href":"saas\/adding_akv.html","attributes":{"data-id":"adding_akv"},"menu":{"hasChildren":false},"tocID":"adding_akv-d27248e11329","next":"adding_akv-d27248e11329"},{"title":"Adding KMIP servers","shortdesc":"<p class=\"shortdesc\">To manage your Key Encryption Key and self-encrypting drive passwords on a Rubrik         cluster using a KMIP-compliant external key manager, you must add the details of the KMIP         server in <span class=\"ph\">RSC<\/span>.<\/p>","href":"saas\/adding_kmip_server.html","attributes":{"data-id":"adding_kmip_server"},"menu":{"hasChildren":false},"tocID":"adding_kmip_server-d27248e11351","next":"adding_kmip_server-d27248e11351"},{"title":"Editing KMS","shortdesc":"<p class=\"shortdesc\">Edit the KMS credentials to update configuration details for an existing KMS instance         as per the KMS type.<\/p>","href":"saas\/editing_kms.html","attributes":{"data-id":"editing_kms"},"menu":{"hasChildren":false},"tocID":"editing_kms-d27248e11379","topics":[]},{"title":"Deleting KMS","shortdesc":"<p class=\"shortdesc\">Delete an AWS KMS key manager, Azure Key Vault, or KMIP server when it is no longer         needed and no particular KMS is currently encrypting any data locations.<\/p>","href":"saas\/deleting_kms.html","attributes":{"data-id":"deleting_kms"},"menu":{"hasChildren":false},"tocID":"deleting_kms-d27248e11390","topics":[]}]}};